using Contoso.Orders;

namespace Contoso.Orders.Tests;

[TestClass]
public sealed class OrderServiceTests
{
    private readonly OrderService _service;

    public OrderServiceTests()
    {
        _service = new OrderService();
    }

    private static List<OrderItem> CreateSampleItems(int count = 1) =>
        Enumerable.Range(1, count).Select(i => new OrderItem
        {
            ProductName = $"Product {i}",
            Price = 10.00m * i,
            Quantity = i
        }).ToList();

    [TestMethod]
    public void CreateOrder_WithValidItems_ReturnsOrderWithCorrectTotal()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 25.00m, Quantity = 2 },
            new() { ProductName = "Gadget", Price = 15.50m, Quantity = 3 }
        };

        // Act
        var order = _service.CreateOrder("customer-1", items);

        // Assert
        Assert.AreEqual(96.50m, order.Total); // (25*2) + (15.50*3)
    }

    [TestMethod]
    public void CreateOrder_WithValidItems_AssignsNonEmptyId()
    {
        // Arrange
        var items = CreateSampleItems();

        // Act
        var order = _service.CreateOrder("customer-1", items);

        // Assert
        Assert.IsNotNull(order.Id);
        Assert.IsNotEmpty(order.Id);
    }

    [TestMethod]
    public void CreateOrder_WithValidItems_SetsCustomerId()
    {
        // Arrange
        var items = CreateSampleItems();

        // Act
        var order = _service.CreateOrder("customer-42", items);

        // Assert
        Assert.AreEqual("customer-42", order.CustomerId);
    }

    [TestMethod]
    public void CreateOrder_WithValidItems_SetsCreatedAtToRecentTime()
    {
        // Arrange
        var items = CreateSampleItems();
        var before = DateTime.UtcNow;

        // Act
        var order = _service.CreateOrder("customer-1", items);

        // Assert
        var after = DateTime.UtcNow;
        Assert.IsGreaterThan(before.AddSeconds(-1), order.CreatedAt);
        Assert.IsLessThan(after.AddSeconds(1), order.CreatedAt);
    }

    [TestMethod]
    public void CreateOrder_WithNullCustomerId_ThrowsArgumentNullException()
    {
        // Arrange
        var items = CreateSampleItems();

        // Act & Assert
        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _service.CreateOrder(null!, items));
        Assert.AreEqual("customerId", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_WithNullItems_ThrowsArgumentNullException()
    {
        // Act & Assert
        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _service.CreateOrder("customer-1", null!));
        Assert.AreEqual("items", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_WithEmptyItems_ThrowsInvalidOperationException()
    {
        // Arrange
        var emptyItems = new List<OrderItem>();

        // Act & Assert
        var ex = Assert.ThrowsExactly<InvalidOperationException>(
            () => _service.CreateOrder("customer-1", emptyItems));
        Assert.Contains("no items", ex.Message, StringComparison.OrdinalIgnoreCase);
    }

    [TestMethod]
    public void GetOrder_WithExistingId_ReturnsOrder()
    {
        // Arrange
        var items = CreateSampleItems();
        var created = _service.CreateOrder("customer-1", items);

        // Act
        var retrieved = _service.GetOrder(created.Id);

        // Assert
        Assert.IsNotNull(retrieved);
        Assert.AreEqual(created.Id, retrieved.Id);
    }

    [TestMethod]
    public void GetOrder_WithNonExistingId_ReturnsNull()
    {
        // Act
        var result = _service.GetOrder("non-existent-id");

        // Assert
        Assert.IsNull(result);
    }

    [TestMethod]
    public void GetOrdersByCustomer_WithMatchingOrders_ReturnsAllCustomerOrders()
    {
        // Arrange
        _service.CreateOrder("customer-A", CreateSampleItems());
        _service.CreateOrder("customer-A", CreateSampleItems(2));
        _service.CreateOrder("customer-B", CreateSampleItems());

        // Act
        var orders = _service.GetOrdersByCustomer("customer-A");

        // Assert
        Assert.HasCount(2, orders);
    }

    [TestMethod]
    public void GetOrdersByCustomer_WithNoMatchingOrders_ReturnsEmptyList()
    {
        // Arrange
        _service.CreateOrder("customer-A", CreateSampleItems());

        // Act
        var orders = _service.GetOrdersByCustomer("customer-Z");

        // Assert
        Assert.IsEmpty(orders);
    }

    [TestMethod]
    public void CreateOrder_MultipleItems_CalculatesTotalCorrectly()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "A", Price = 5.00m, Quantity = 4 },
            new() { ProductName = "B", Price = 12.50m, Quantity = 1 },
            new() { ProductName = "C", Price = 3.00m, Quantity = 10 }
        };

        // Act
        var order = _service.CreateOrder("customer-1", items);

        // Assert — (5*4) + (12.50*1) + (3*10) = 20 + 12.50 + 30 = 62.50
        Assert.AreEqual(62.50m, order.Total);
    }

    [TestMethod]
    public void CreateOrder_StoresOrderForRetrieval()
    {
        // Arrange & Act
        var created = _service.CreateOrder("customer-1", CreateSampleItems());

        // Assert — order is retrievable after creation
        var retrieved = _service.GetOrder(created.Id);
        Assert.AreSame(created, retrieved);
    }
}

