         {
             new() { ProductName = "A", Price = 5.00m, Quantity = 4 },
             new() { ProductName = "B", Price = 12.50m, Quantity = 1 },
             new() { ProductName = "C", Price = 3.00m, Quantity = 10 }
         };

         // Act
         var order = _service.CreateOrder("customer-1", items);

         // Assert — (5*4) + (12.50*1) + (3*10) = 20 + 12.50 + 30 = 62.50
         Assert.AreEqual(62.50m, order.Total);
     }

